enhancedAnovaResults <- if (requireNamespace("jmvcore", quietly=TRUE)) R6::R6Class(
    "enhancedAnovaResults",
    inherit = jmvcore::Group,
    active = list(
        status = function() private$.items[["status"]],
        modelSummary = function() private$.items[["modelSummary"]],
        descriptivesSection = function() private$.items[["descriptivesSection"]],
        effectSizesSection = function() private$.items[["effectSizesSection"]],
        assumptionsSection = function() private$.items[["assumptionsSection"]],
        contrasts = function() private$.items[["contrasts"]],
        orderRestrictions = function() private$.items[["orderRestrictions"]],
        postHocSection = function() private$.items[["postHocSection"]],
        marginalMeansSection = function() private$.items[["marginalMeansSection"]],
        simpleEffectsSection = function() private$.items[["simpleEffectsSection"]],
        nonparametric = function() private$.items[["nonparametric"]],
        plots = function() private$.items[["plots"]],
        qqPlot = function() private$.items[["qqPlot"]],
        residualPlot = function() private$.items[["residualPlot"]],
        raincloudPlot = function() private$.items[["raincloudPlot"]],
        savedColumns = function() private$.items[["savedColumns"]],
        residsOV = function() private$.items[["residsOV"]],
        studentizedResidsOV = function() private$.items[["studentizedResidsOV"]],
        standardizedResidsOV = function() private$.items[["standardizedResidsOV"]],
        predictOV = function() private$.items[["predictOV"]],
        apa = function() private$.items[["apa"]],
        teaching = function() private$.items[["teaching"]],
        publication = function() private$.items[["publication"]],
        reproducibility = function() private$.items[["reproducibility"]],
        about = function() private$.items[["about"]]),
    private = list(),
    public=list(
        initialize=function(options) {
            super$initialize(
                options=options,
                name="",
                title="JASP Enhanced ANOVA")
            self$add(jmvcore::Html$new(
                options=options,
                name="status",
                title="Implementation Status"))
            self$add(jmvcore::Html$new(
                options=options,
                name="modelSummary",
                title="Model Summary"))
            self$add(jmvcore::Html$new(
                options=options,
                name="descriptivesSection",
                title="Descriptive Statistics",
                visible="(descriptives)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="effectSizesSection",
                title="Effect Sizes"))
            self$add(jmvcore::Html$new(
                options=options,
                name="assumptionsSection",
                title="Assumption Checks and Diagnostics"))
            self$add(jmvcore::Html$new(
                options=options,
                name="contrasts",
                title="Contrasts"))
            self$add(jmvcore::Html$new(
                options=options,
                name="orderRestrictions",
                title="Bayesian and Order Restricted Hypotheses"))
            self$add(jmvcore::Html$new(
                options=options,
                name="postHocSection",
                title="Post Hoc Tests",
                visible="(postHoc)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="marginalMeansSection",
                title="Estimated Marginal Means",
                visible="(marginalMeans)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="simpleEffectsSection",
                title="Simple Main Effects",
                visible="(simpleEffects)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="nonparametric",
                title="Nonparametric Alternatives",
                visible="(kruskalWallis)"))
            self$add(jmvcore::Html$new(
                options=options,
                name="plots",
                title="Plots"))
            self$add(jmvcore::Image$new(
                options=options,
                name="qqPlot",
                title="Q-Q Plot of Residuals",
                visible="(qqPlotResiduals)",
                width=520,
                height=420,
                renderFun=".qqPlot"))
            self$add(jmvcore::Image$new(
                options=options,
                name="residualPlot",
                title="Residual Plot",
                visible="(residualPlots)",
                width=520,
                height=420,
                renderFun=".residualPlot"))
            self$add(jmvcore::Image$new(
                options=options,
                name="raincloudPlot",
                title="Raincloud Plot",
                visible="(raincloudPlots)",
                width=640,
                height=440,
                renderFun=".raincloudPlot"))
            self$add(jmvcore::Html$new(
                options=options,
                name="savedColumns",
                title="Saved Dataset Columns"))
            self$add(jmvcore::Output$new(
                options=options,
                name="residsOV",
                title="Residuals",
                varTitle="Residuals",
                varDescription="Residuals from JASP Enhanced ANOVA",
                measureType="continuous",
                clearWith=list(
                    "dependent",
                    "fixedFactors",
                    "covariates")))
            self$add(jmvcore::Output$new(
                options=options,
                name="studentizedResidsOV",
                title="Studentized residuals",
                varTitle="Studentized residuals",
                varDescription="Studentized residuals from JASP Enhanced ANOVA",
                measureType="continuous",
                clearWith=list(
                    "dependent",
                    "fixedFactors",
                    "covariates")))
            self$add(jmvcore::Output$new(
                options=options,
                name="standardizedResidsOV",
                title="Standardized residuals",
                varTitle="Standardized residuals",
                varDescription="Standardized residuals from JASP Enhanced ANOVA",
                measureType="continuous",
