            self$add(jmvcore::Output$new(
                options=options,
                name="predictOV",
                title="Predicted values",
                varTitle="Predicted values",
                varDescription="Predicted values from JASP Enhanced ANOVA",
                measureType="continuous",
                clearWith=list(
                    "dependent",
