                options=options,
                name="reproducibility",
                title="Reproducibility"))
            self$add(jmvcore::Html$new(
                options=options,
                name="about",
                title="About and Citation"))}))

enhancedAnovaBase <- if (requireNamespace("jmvcore", quietly=TRUE)) R6::R6Class(
    "enhancedAnovaBase",
    inherit = jmvcore::Analysis,
    public = list(
        initialize = function(options, data=NULL, datasetId="", analysisId="", revision=0) {
            super$initialize(
                package = "jaspEnhancedAnova",
                name = "enhancedAnova",
                version = c(0,1,0),
                options = options,
                results = enhancedAnovaResults$new(options=options),
                data = data,
                datasetId = datasetId,
                analysisId = analysisId,
                revision = revision,
                pause = NULL,
                completeWhenFilled = FALSE,
                requiresMissings = FALSE,
                weightsSupport = 'none')
        }))

#' JASP Enhanced ANOVA
#'
#' jamovi-native shell for the full JASP classical ANOVA option surface, 
#' including planned feature parity for corrections, contrasts, post hoc 
#' tests, plots, marginal means, simple effects, nonparametric alternatives, 
#' export functions, APA reporting, teaching mode, and reproducibility.
#' 
#' @param data .
#' @param dependent .
#' @param fixedFactors .
