#'   \code{results$marginalMeansSection} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$simpleEffectsSection} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$nonparametric} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$plots} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$qqPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$residualPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$raincloudPlot} \tab \tab \tab \tab \tab an image \cr
#'   \code{results$savedColumns} \tab \tab \tab \tab \tab a html \cr
#'   \code{results$residsOV} \tab \tab \tab \tab \tab an output \cr
#'   \code{results$studentizedResidsOV} \tab \tab \tab \tab \tab an output \cr
#'   \code{results$standardizedResidsOV} \tab \tab \tab \tab \tab an output \cr
